import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine(); // Use nextLine() to read the entire line

        // Define a maximum length for the buffer
        int maxLength = 10;

        // Copy the user input into the buffer with bounds checking
        char[] buffer = new char[maxLength];
        int length = Math.min(input.length(), maxLength);

        for (int i = 0; i < length; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Name: " + new String(buffer, 0, length)); // Create a String with specified offset and length
    }
}

